<html>
<head>
  <meta charset="utf-8">
  <title>Dashboard Widget Leak Demo — Leaky vs Fixed</title>
  <style>
    body { font-family: system-ui, -apple-system, Segoe UI, Roboto, "Helvetica Neue", Arial; margin: 16px; color: #111; }
    h1 { margin: 0 0 8px 0; }
    .container { display: flex; gap: 16px; align-items: flex-start; }
    .col { border: 1px solid #ddd; padding: 12px; width: 48%; box-sizing: border-box; border-radius: 6px; background: #fafafa; }
    .controls { display:flex; gap:8px; margin-bottom:8px; }
    .widget { border: 1px solid #ccc; padding:8px; margin: 8px 0; border-radius:6px; background: #fff; display:flex; justify-content:space-between; align-items:center; }
    .widget .left { display:flex; gap: 12px; align-items:center; }
