    .note { margin-top: 12px; background: #fffbe6; padding: 8px; border-radius:6px; border:1px solid #ffe58f; }
    .explain { margin-top:12px; font-size:13px; }
    .big-count { font-weight:700; font-size: 16px; }
  </style>
</head>
<body>
  <h1>Dashboard Widget Leak Demo</h1>
  <p class="small">Add and remove widgets repeatedly. The <strong>Leaky version</strong> intentionally keeps references/listeners around when a widget is removed. The <strong>Fixed version</strong> cleans up. Watch the counters increase in the leaky column.</p>

  <div class="container">
    <div class="col" id="leaky-col">
      <h2>Leaky version</h2>
      <div class="controls">
        <button id="leaky-add">Add widget</button>
        <button id="leaky-remove">Remove last</button>
      </div>
      <div id="leaky-widgets"></div>
      <div class="stats">
        Timers running: <span id="leaky-timers" class="big-count">0</span><br>
        Stored references in leak map: <span id="leaky-map" class="big-count">0</span>
      </div>
      <div class="note">
        This version: when a widget is removed from the DOM we intentionally do NOT remove event listeners, interval timers, nor clear references kept in a global map. Over time those resources accumulate.
      </div>
    </div>

    <div class="col" id="fixed-col">
      <h2>Fixed version</h2>
      <div class="controls">
        <button id="fixed-add">Add widget</button>
        <button id="fixed-remove">Remove last</button>
      </div>
      <div id="fixed-widgets"></div>
      <div class="stats">
        Timers running: <span id="fixed-timers" class="big-count">0</span><br>
        Stored references in registry: <span id="fixed-map" class="big-count">0</span>
      </div>
      <div class="note">
        This version: when a widget is removed we stop timers, remove event listeners, and clear references so GC can reclaim memory.
      </div>
    </div>
  </div>

  <div class="explain">
    <h3>Why blaming the garbage collector is usually wrong here</h3>
    <p class="small">The garbage collector only reclaims objects that are no longer reachable from roots (like global variables, DOM tree, active event listeners, timers, closures referenced by live code). If your code keeps references (for example in global maps, or via active event listeners or intervals), the GC is doing the right thing by keeping them. The problem is that your code created those roots and never cleared them. In other words, the bug is in retaining references, not in the GC.</p>
  </div>

  <script>
    // Demo implementation:
    // - Leaky version keeps references in leakMap and never clears them.
    // - Fixed version keeps references in registry and cleans them on remove.
    (function () {
      // Utilities for DOM creation
      function el(tag, props, ...children) {
        const e = document.createElement(tag);
        if (props) Object.keys(props).forEach(k => {
          if (k === 'class') e.className = props[k];
          else if (k === 'text') e.textContent = props[k];
          else e.setAttribute(k, props[k]);
        });
        children.forEach(c => {
          if (typeof c === 'string') e.appendChild(document.createTextNode(c));
          else if (c) e.appendChild(c);
        });
        return e;
      }

      // ---------- Leaky version ----------
      const leaky = {
        container: document.getElementById('leaky-widgets'),
        addBtn: document.getElementById('leaky-add'),
        removeBtn: document.getElementById('leaky-remove'),
        timersCountEl: document.getElementById('leaky-timers'),
        mapCountEl: document.getElementById('leaky-map'),

        // Intentionally global leak map: holds data about removed widgets and timer ids.
        leakMap: new Map(),
        nextId: 1,
        nodes: [] // current DOM nodes (so we can remove last)
      };

      // Create widget that increments a counter on an interval, listens for clicks,
      // and stores references in leakMap when removed (but we won't clean them).
      function createLeakyWidget() {
        const id = 'L' + leaky.nextId++;
        const wrapper = el('div', { class: 'widget', 'data-id': id });
        const left = el('div', { class: 'left' });
        const title = el('div', { text: id + ' (leaky)' });
        const counterEl = el('div', { class: 'small', text: '0' });
        left.appendChild(title);
        left.appendChild(counterEl);

        const removeBtn = el('button', { text: 'Remove' });
        wrapper.appendChild(left);
        wrapper.appendChild(removeBtn);

        // Start an interval timer that updates the counter element
        let counter = 0;
        const timerId = setInterval(() => {
          counter++;
          counterEl.textContent = String(counter);
        }, 1000);

        // Add an event listener on wrapper (we'll never explicitly remove it in the "leaky" path)
        function onClick(e) {
          console.log('Leaky widget clicked', id);
        }
        wrapper.addEventListener('click', onClick);

        // When removed via UI remove button we remove DOM element but intentionally keep
        // references in leakMap and do NOT clear the interval nor remove listeners.
        removeBtn.addEventListener('click', () => {
          // remove DOM node from view
          if (wrapper.parentNode) wrapper.parentNode.removeChild(wrapper);
          // store references in global leakMap (simulates some cache/registry)
          leaky.leakMap.set(id, {
            wrapperRef: wrapper, // holds the DOM node -> keeps entire subtree reachable
            counterElRef: counterEl,
            onClickRef: onClick,
            timerIdRef: timerId
          });
          // Also remove from nodes array
          const idx = leaky.nodes.indexOf(wrapper);
          if (idx >= 0) leaky.nodes.splice(idx, 1);
          updateLeakyStats();
        });

        leaky.nodes.push(wrapper);
        leaky.container.appendChild(wrapper);
        updateLeakyStats();
      }

      function updateLeakyStats() {
        // Count timers: we count items in leakMap (these are timers for removed widgets)
        // plus currently live widgets' timers. But in this leaky demo, we never clear intervals,
        // so total timers = current nodes + leakMap size
        const currentTimers = leaky.nodes.length; // each live node has a timer
        const leakedTimers = leaky.leakMap.size;
        leaky.timersCountEl.textContent = String(currentTimers + leakedTimers);
        leaky.mapCountEl.textContent = String(leaky.leakMap.size);
      }

      leaky.addBtn.addEventListener('click', () => createLeakyWidget());
      leaky.removeBtn.addEventListener('click', () => {
        // Remove last widget via dashboard remove (like a "bulk remove" action)
        const last = leaky.nodes[leaky.nodes.length - 1];
        if (last) {
          // trigger its remove button click to reuse same removal behavior
          const btn = last.querySelector('button');
          if (btn) btn.click();
        }
      });

      // ---------- Fixed version ----------
      const fixed = {
        container: document.getElementById('fixed-widgets'),
        addBtn: document.getElementById('fixed-add'),
        removeBtn: document.getElementById('fixed-remove'),
        timersCountEl: document.getElementById('fixed-timers'),
        mapCountEl: document.getElementById('fixed-map'),

        registry: new Map(),
        nextId: 1,
        nodes: []
      };

      // Create a widget but on remove we clean timers/listeners/refs so GC can reclaim them
      function createFixedWidget() {
        const id = 'F' + fixed.nextId++;
        const wrapper = el('div', { class: 'widget', 'data-id': id });
        const left = el('div', { class: 'left' });
        const title = el('div', { text: id + ' (fixed)' });
        const counterEl = el('div', { class: 'small', text: '0' });
        left.appendChild(title);
        left.appendChild(counterEl);

        const removeBtn = el('button', { text: 'Remove' });
        wrapper.appendChild(left);
        wrapper.appendChild(removeBtn);

        // Start an interval timer that updates the counter element
        let counter = 0;
        const timerId = setInterval(() => {
          counter++;
          counterEl.textContent = String(counter);
        }, 1000);

        // Event listener
        function onClick(e) {
          console.log('Fixed widget clicked', id);
        }
        wrapper.addEventListener('click', onClick);

        // Register resources so we can clean them later
        fixed.registry.set(id, {
          wrapper,
          counterEl,
          timerId,
          onClick
        });

        removeBtn.addEventListener('click', () => {
          // remove DOM node
          if (wrapper.parentNode) wrapper.parentNode.removeChild(wrapper);

          // Proper cleanup:
          const entry = fixed.registry.get(id);
          if (entry) {
            // stop timer
            clearInterval(entry.timerId);
            // remove event listener
            try {
              entry.wrapper.removeEventListener('click', entry.onClick);
            } catch (e) { /* ignore */ }

            // remove references from registry so they become unreachable
            fixed.registry.delete(id);
          }

          // Also remove from nodes array
          const idx = fixed.nodes.indexOf(wrapper);
          if (idx >= 0) fixed.nodes.splice(idx, 1);

          updateFixedStats();
        });

        fixed.nodes.push(wrapper);
        fixed.container.appendChild(wrapper);
        updateFixedStats();
      }

      function updateFixedStats() {
        // timers running = current nodes' timers (each active widget has a timer)
        // + registry size (if we weren't cleaning there would be leaked timers)
        const currentTimers = fixed.nodes.length;
        const registryCount = fixed.registry.size;
        fixed.timersCountEl.textContent = String(currentTimers);
        fixed.mapCountEl.textContent = String(registryCount);
      }

      fixed.addBtn.addEventListener('click', () => createFixedWidget());
      fixed.removeBtn.addEventListener('click', () => {
        const last = fixed.nodes[fixed.nodes.length - 1];
        if (last) {
          const btn = last.querySelector('button');
          if (btn) btn.click();
        }
      });

      // Add a few initial widgets for convenience
      for (let i = 0; i < 2; i++) { createLeakyWidget(); createFixedWidget(); }

      // Periodically refresh stats (in case user uses remove/add outside clicks)
      setInterval(() => {
        updateLeakyStats();
        updateFixedStats();
      }, 500);

      // Expose some things to window for manual inspection in console if needed
      window.__demo = { leaky, fixed };

      // Optional: add a "simulate repeated add/remove" to show leak growth faster
      let autoHandle = null;
      function startAutoCycle() {
        if (autoHandle) return;
        let toggle = true;
        autoHandle = setInterval(() => {
          // Add a widget to each
          createLeakyWidget();
          createFixedWidget();
          // Remove last from each
          const lLast = leaky.nodes[leaky.nodes.length - 1];
          if (lLast) {
            const btn = lLast.querySelector('button');
            if (btn) btn.click();
          }
          const fLast = fixed.nodes[fixed.nodes.length - 1];
          if (fLast) {
            const btn = fLast.querySelector('button');
            if (btn) btn.click();
          }
        }, 300);
      }
      function stopAutoCycle() {
        if (!autoHandle) return;
        clearInterval(autoHandle);
        autoHandle = null;
      }

      // Create control buttons at top-right floating (not in DOM) for convenience
      const simControls = el('div', { style: 'position:fixed; right:16px; top:16px; background:#fff; padding:8px; border:1px solid #ccc; border-radius:6px;'});
      const autoStart = el('button', { text: 'Start auto add/remove' });
      const autoStop = el('button', { text: 'Stop auto' });
      simControls.appendChild(autoStart);
      simControls.appendChild(autoStop);
      document.body.appendChild(simControls);
      autoStart.addEventListener('click', startAutoCycle);
      autoStop.addEventListener('click', stopAutoCycle);

    })();
  </script>
</body>
</html>

Explanation (summary)
- The leaky version holds onto DOM node references, listener functions, and interval IDs in the global leakMap after widgets are removed. Because those references are roots still reachable from global state, the garbage collector cannot reclaim those objects — so memory (and the number of timers/listeners) grows.
- The fixed version stops the interval timers, removes event listeners, and deletes the registry entries so no live root points to those objects anymore. Now GC can reclaim them.
- Therefore, the GC is not "at fault" — it's doing its job. The real bug is retaining references to objects you no longer need. Use proper cleanup (remove listeners, clear timers, delete references, or use WeakMap/WeakRef for caches) to avoid leaks.

